12	import lombok.RequiredArgsConstructor;
13	import lombok.extern.slf4j.Slf4j;
14	import org.springframework.stereotype.Component;
15	
16	@Slf4j
17	@Component
18	@RequiredArgsConstructor
19	public class DifferentAttributesWithLockAcquiredHandler implements FingerprintHandler {
20	
21	    private final EntityService entityService;
22	    private final EntityStateMachine stateMachine;
23	
24	    @Override
25	    public StatusOr<Entity> handle(IngestionRequest req, Entity e, String reqFp) {
26	
27	        log.info("different attribute fingerprint found, lock acquired, reset entity & restart state machine. entityId={}",
28	                e.getId());
29	
30	        e.setAttributeFingerprint(reqFp);
31	        e.setProcessingStage(EntityStage.PENDING.toString());
32	        e.setProcessingCode(0);
33	        e.setInterrupted(false);
34	        e.setLastReqVersion(req.getVersion());
35	        e.setProcessingResult("{}");
36	        e.setErrorMessage("");
37	
38	        boolean ok = entityService.updateProcessingState(e);
39	        if (!ok) {
40	            log.error("Failed to reset processing state, entityId={}", e.getId());
41	            return StatusOr.error(Constants.BusinesCode.STATE_MACHINE_DB_PROCESSING_STATE_UPDATE_FAILED,
42	                    "failed to reset processing state");
43	        }
44	
45	        return stateMachine.start(req.getRequestId(), req.isAsync(), e);
46	    }
47	}
