3	import com.fasterxml.jackson.core.type.TypeReference;
4	import com.fasterxml.jackson.databind.ObjectMapper;
5	import com.fasterxml.jackson.databind.node.ObjectNode;
6	import com.fortinet.nac.classification.api.dto.label.LabelReference;
7	import com.fortinet.nac.classification.api.dto.label.ObjectNodeIdempotentRequest;
8	import com.fortinet.nac.classification.service.ObjectNodeService;
9	import com.fortinet.nac.classification.service.RuleEngineService;
10	import com.fortinet.nac.common.enums.EntityProcessingCode;
11	import com.fortinet.nac.common.dto.EntityDTO;
12	import lombok.RequiredArgsConstructor;
13	import org.springframework.stereotype.Service;
14	import org.springframework.transaction.annotation.Transactional;
15	
16	import java.util.ArrayList;
17	import java.util.HashMap;
18	import java.util.List;
19	import java.util.Map;
20	
21	@Service
22	@RequiredArgsConstructor
23	public class LabelService {
24	    // Label stage processing codes are defined in EntityProcessingCode.Label class
25	    // Current success code: EntityProcessingCode.SUCCESS (0)
26	    // To add new codes, follow the convention in EntityProcessingCode.java:
27	    // - 21xx for temporary/retryable errors
28	    // - 22xx for permanent errors
29	    // Example: public static final int MY_NEW_ERROR = 2250;
30	
31	    private final ObjectMapper objectMapper;
32	
33	    private final RuleEngineService ruleEngineService;
34	
35	    private final ObjectNodeService objectNodeService;
36	
37	    /**
38	     * @return ObjectNode:
39	     *      Success: { "code": 0, "data": { ... } }
40	     *      Failure: { "code": <non-zero>, "errMessage": "..." }
41	     */
42	    public ObjectNode label(EntityDTO dto) {
43	        return StageExecutor.execute(dto, this::doLabel);
44	    }
45	
46	    @Transactional
47	    public ObjectNode doLabel(EntityDTO dto) {
48	        Map<String, Object> input = objectMapper.convertValue(dto, new TypeReference<>() {});
49	        ObjectNodeIdempotentRequest request = new ObjectNodeIdempotentRequest();
50	        request.setObjectId(dto.getId());
51	        Map<String, Object> properties = new HashMap<>();
52	        properties.put("EntityDTO", dto);
53	        request.setProperties(properties);
54	
55	        if(dto.getUserId() != null) {
56	            input = ruleEngineService.execute("USER", "USER", input);
57	            request.setNodeType("USER");
58	        }
59	
60	        if (dto.getHostId() != null) {
61	            input = ruleEngineService.execute("HOST", "HOST", input);
62	            request.setNodeType("HOST");
63	        }
64	
65	        if (dto.getAdapterId() != null) {
66	            input = ruleEngineService.execute("ADAPTER", "ADAPTER", input);
67	            request.setNodeType("ADAPTER");
68	        }
69	
70	        @SuppressWarnings("unchecked")
71	        Map<String, String> labels = (Map<String, String>) input.get("__labels__");
72	        List<LabelReference> labelRefs = new ArrayList<>();
73	        for (Map.Entry<String, String> entry : labels.entrySet()) {
74	            LabelReference labelRef = new LabelReference();
75	            labelRef.setLabelType(entry.getKey());
76	            labelRef.setName(entry.getValue());
77	            labelRefs.add(labelRef);
78	        }
79	        request.setLabels(labelRefs);
80	        objectNodeService.handleLabelAssociations(request);
81	
82	        // Successful processing
83	        ObjectNode res = objectMapper.createObjectNode();
84	        res.put("code", EntityProcessingCode.SUCCESS);
85	        res.set("data", objectMapper.valueToTree(labels));
86	
87	        // TODO(Chong): Label output can be populated here in future
88	        // dto.setEntityLabels(...);
89	        // dto.setUserLabels(...);
90	        // dto.setHostLabels(...);
91	
92	        return res;
93	    }
94	}
