51	    @Bean("policyReprocessJobExecutor")
52	    public Executor policyReprocessJobExecutor() {
53	        int effectiveCoreSize = Math.max(1, jobCoreSize);
54	        int effectiveMaxSize = Math.max(effectiveCoreSize, jobMaxSize);
55	        ThreadPoolTaskExecutor executor = new ThreadPoolTaskExecutor();
56	        executor.setCorePoolSize(effectiveCoreSize);
57	        executor.setMaxPoolSize(effectiveMaxSize);
58	        executor.setQueueCapacity(jobQueueCapacity);
59	        executor.setKeepAliveSeconds(jobKeepAliveSeconds);
60	        executor.setThreadNamePrefix("policy-reprocess-job-");
61	        executor.setRejectedExecutionHandler(new ThreadPoolExecutor.CallerRunsPolicy());
62	        executor.initialize();
63	        return executor;
