2	
3	import com.fortinet.nac.ingestion.entity.Entity;
4	import com.fortinet.nac.ingestion.service.EntityService;
5	import io.micrometer.core.instrument.Counter;
6	import io.micrometer.core.instrument.MeterRegistry;
7	import io.micrometer.core.instrument.Timer;
8	import lombok.RequiredArgsConstructor;
9	import lombok.extern.slf4j.Slf4j;
10	import org.springframework.beans.factory.annotation.Value;
11	import org.springframework.scheduling.annotation.Scheduled;
12	import org.springframework.stereotype.Component;
13	
14	import javax.annotation.PostConstruct;
15	import javax.annotation.Resource;
16	import java.time.Duration;
17	import java.util.ArrayList;
18	import java.util.List;
19	import java.util.concurrent.CompletableFuture;
20	import java.util.concurrent.Executor;
21	import java.util.concurrent.TimeUnit;
22	import java.util.concurrent.atomic.AtomicBoolean;
23	import java.util.concurrent.atomic.AtomicInteger;
24	
25	@Slf4j
26	@Component
27	@RequiredArgsConstructor
28	public class StuckEntityRecoveryJob {
29	
30	    private final EntityService entityService;
31	    private final EntityRecoveryService recoveryService;
32	    private final MeterRegistry meterRegistry;
33	
34	    @Resource(name = "ingestionRecoveryExecutor")
35	    private Executor ingestionRecoveryExecutor;
36	
37	    @Value("${ingestion.recovery.enabled:true}")
38	    private boolean enabled;
39	
40	    /**
41	     * How long without updates before we treat an entity as “suspected stuck”.
42	     *  Note:  make sure staleThresholdSeconds > Constants.RedisKeys.ENTITY_PROCESS_LOCK_TTL
43	     */
44	    @Value("${ingestion.recovery.stale-threshold-seconds:80}")
45	    private long staleThresholdSeconds;
46	
47	    /**
48	     * Max number of candidates to pull from DB per scan.
49	     */
50	    @Value("${ingestion.recovery.batch-size:50}")
51	    private int batchSize;
52	
53	    @Value("${ingestion.recovery.rate-limit-per-second:20}")
54	    private int rateLimitPerSecond;
55	
56	    private Counter scannedCounter;
57	    private Counter recoveredCounter;
58	    private Counter failedCounter;
59	    private Counter lockBusyCounter;
60	
61	    @PostConstruct
62	    public void init() {
63	        scannedCounter = Counter.builder("ingestion_recovery_scanned_total").register(meterRegistry);
64	        recoveredCounter = Counter.builder("ingestion_recovery_recovered_total").register(meterRegistry);
65	        failedCounter = Counter.builder("ingestion_recovery_failed_total").register(meterRegistry);
66	        lockBusyCounter = Counter.builder("ingestion_recovery_lock_busy_total").register(meterRegistry);
67	        log.info("StuckEntityRecoveryJob: bean initialized, enabled={}", enabled);
68	    }
69	
70	    // Periodic DB scan with fallback recovery
71	    @Scheduled(fixedDelayString = "${ingestion.recovery.fixed-delay-ms:30000}")
72	    public void recoverStuckEntities() {
73	        if (!enabled) {
74	            return;
75	        }
76	
77	        // Keep run-level details at DEBUG to avoid noisy periodic INFO logs when system is healthy.
78	        log.debug("StuckEntityRecoveryJob: starting recovery job run with config: staleThresholdSeconds={}, batchSize={}",
79	                staleThresholdSeconds, batchSize);
80	
81	        Timer.Sample sample = Timer.start(meterRegistry);
82	        long startNs = System.nanoTime();
83	
84	        String resultTag = "success";
85	
86	        try {
87	            Duration threshold = Duration.ofSeconds(staleThresholdSeconds);
88	            int effectiveBatchSize = Math.max(1, batchSize);
89	            RecoveryRateLimiter rateLimiter = new RecoveryRateLimiter(rateLimitPerSecond, meterRegistry);
90	
91	            List<Entity> candidates = entityService.findStuckEntities(threshold, effectiveBatchSize);
92	            if (!candidates.isEmpty()) {
93	                log.info("StuckEntityRecoveryJob: found {} candidates for recovery", candidates.size());
94	                for (Entity e : candidates) {
95	                    log.info("StuckEntityRecoveryJob: candidate entity id={}, stage={}, code={}, interrupted={}, updatedAt={}",
96	                        e.getId(), e.getProcessingStage(), e.getProcessingCode(), e.isInterrupted(), e.getUpdatedAt());
97	                }
98	            }
99	            scannedCounter.increment(candidates.size());
100	
101	            if (candidates.isEmpty()) {
102	                log.debug("StuckEntityRecoveryJob: no candidates, skip this round.");
103	                return;
104	            }
105	
106	            log.info("StuckEntityRecoveryJob: processing {} candidates", candidates.size());
107	
108	            AtomicInteger recovered = new AtomicInteger(0);
109	            AtomicBoolean hasFailure = new AtomicBoolean(false);
110	            List<CompletableFuture<Void>> futures = new ArrayList<>(candidates.size());
111	            for (Entity e : candidates) {
112	                long entityId = e.getId();
113	
114	                futures.add(CompletableFuture.runAsync(() -> {
115	                    try {
116	                        rateLimiter.acquire();
117	                        EntityRecoveryService.RecoveryResult rr =
118	                                recoveryService.recoverIfStuck(entityId, "db-job");
119	
120	                        if (!rr.isLockAcquired()) {
121	                            // Another thread is processing it, so record metric and check again in the next round.
122	                            lockBusyCounter.increment();
123	                            return;
124	                        }
125	
126	                        if (rr.isFinished()) {
127	                            // Already ENFORCED or processingCode != 0.
128	                            log.info("StuckEntityRecoveryJob: entityId={} already finished, skip.", entityId);
129	                            return;
130	                        }
131	
132	                        if (rr.isRecoveryStarted()) {
133	                            recovered.incrementAndGet();
134	                            recoveredCounter.increment();
135	                        }
136	                    } catch (Exception ex) {
137	                        failedCounter.increment();
138	                        hasFailure.set(true);
139	                        log.error("StuckEntityRecoveryJob: error when recovering entityId={}", entityId, ex);
140	                    }
141	                }, ingestionRecoveryExecutor));
142	            }
143	
144	            CompletableFuture.allOf(futures.toArray(new CompletableFuture[0])).join();
145	            if (hasFailure.get()) {
146	                resultTag = "fail";
147	            }
148	
149	            log.info("StuckEntityRecoveryJob: candidates={}, recovered={}, cost={} ms",
150	                    candidates.size(), recovered.get(),
151	                    TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs));
152	        } finally {
153	            Timer timer = Timer.builder("ingestion_recovery_job_seconds")
154	                    .tag("result", resultTag)
155	                    .register(meterRegistry);
156	            sample.stop(timer);
157	        }
158	    }
159	
160	    private static final class RecoveryRateLimiter {
161	        private static final long ONE_SECOND_NANOS = TimeUnit.SECONDS.toNanos(1);
162	
163	        private final int refillTokensPerSecond;
164	        private final double capacity;
165	        private final Counter waitCounter;
166	
167	        private double availableTokens;
168	        private long lastRefillNanos = System.nanoTime();
169	
170	        private RecoveryRateLimiter(int maxPerSecond, MeterRegistry meterRegistry) {
171	            this.refillTokensPerSecond = Math.max(0, maxPerSecond);
172	            this.capacity = this.refillTokensPerSecond <= 0 ? 0.0 : this.refillTokensPerSecond;
173	            this.availableTokens = this.capacity;
174	            this.waitCounter = meterRegistry.counter("ingestion_recovery_rate_limiter_wait_total");
175	        }
176	
177	        private synchronized void acquire() {
178	            if (refillTokensPerSecond <= 0) {
179	                return;
180	            }
181	
182	            refillTokens();
183	
184	            if (availableTokens < 1.0) {
185	                long waitNanos = nanosUntilNextToken();
186	                if (waitNanos > 0) {
187	                    waitCounter.increment();
188	                    try {
189	                        TimeUnit.NANOSECONDS.sleep(waitNanos);
190	                    } catch (InterruptedException ex) {
191	                        Thread.currentThread().interrupt();
192	                        return;
193	                    }
194	                }
195	                refillTokens();
196	            }
197	
198	            if (availableTokens >= 1.0) {
199	                availableTokens -= 1.0;
200	            } else {
201	                availableTokens = 0.0;
202	            }
203	        }
204	
205	        private void refillTokens() {
206	            long now = System.nanoTime();
207	            long elapsedNanos = now - lastRefillNanos;
208	            if (elapsedNanos <= 0) {
209	                return;
210	            }
211	
212	            double tokensToAdd = (elapsedNanos / (double) ONE_SECOND_NANOS) * refillTokensPerSecond;
213	            if (tokensToAdd <= 0.0) {
214	                return;
215	            }
216	
217	            availableTokens = Math.min(capacity, availableTokens + tokensToAdd);
218	            lastRefillNanos = now;
219	        }
220	
221	        private long nanosUntilNextToken() {
222	            double missingTokens = 1.0 - availableTokens;
223	            if (missingTokens <= 0.0 || refillTokensPerSecond <= 0) {
224	                return 0L;
225	            }
226	            return (long) Math.ceil((missingTokens / refillTokensPerSecond) * ONE_SECOND_NANOS);
227	        }
228	    }
229	}
