package com.fortinet.nac.ingestion.service.stages;

import com.fortinet.nac.common.enums.EntityProcessingCode;
import com.fortinet.nac.common.dto.EntityDTO;

import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ObjectNode;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;

@Service
@RequiredArgsConstructor
public class PolicyService {
    // Policy stage processing codes are defined in EntityProcessingCode.Policy class
    // Current success code: EntityProcessingCode.SUCCESS (0)
    // To add new codes, follow the convention in EntityProcessingCode.java:
    // - 31xx for temporary/retryable errors
    // - 32xx for permanent errors
    // Example: public static final int MY_NEW_ERROR = 3250;

    private final ObjectMapper objectMapper;

    public ObjectNode evaluate(EntityDTO dto) {
        return StageExecutor.execute(dto, this::doEvaluate);
    }

    private ObjectNode doEvaluate(EntityDTO dto) {
        ObjectNode res = objectMapper.createObjectNode();

        ObjectNode data = objectMapper.createObjectNode();
        data.put("policy1", "allow vpn");
        data.put("policy2", "rate limited");

        // Successful processing
        res.put("code", EntityProcessingCode.SUCCESS);
        res.set("data", data);

        // Future logic: save policy decision
        // dto.setPolicyDecision(...);

        return res;
    }
}

